#!/bin/bash

if [[ ! -d "$HOME/.local/share/applications" ]]; then
  mkdir -p "$HOME/.local/share/applications"
fi

cat >"$HOME/.local/share/applications/assurcast-reader.desktop" <<END
[Desktop Entry]
Name=Assurcast Reader
Exec=$HOME/.local/bin/assurcast-reader -open
Icon=assurcast-reader
Type=Application
Categories=Internet;
END

if [[ ! -d "$HOME/.local/share/icons" ]]; then
  mkdir -p "$HOME/.local/share/icons"
fi

# Assurcast brand mark, PNG wrapped in SVG. Source: apple-touch-icon.png 180x180.
# Replace with true vector after Assurcast card #172 ships.
cat >"$HOME/.local/share/icons/assurcast-reader.svg" <<END
<?xml version="1.0" encoding="UTF-8"?>
<svg xmlns="http://www.w3.org/2000/svg" width="256" height="256" viewBox="0 0 256 256">
  <image href="data:image/png;base64," width="256" height="256"/>
</svg>
END
